mapper.select:
SELECT * FROM (
SELECT T.*, ROWNUM AS rn FROM (
SELECT item_id,
item_title,
CREATED_AT
FROM shop_board
ORDER BY item_id desc
) T WHERE ROWNUM <= (#{offset}+1) * #{size}
) WHERE rn > #{offset}  * #{size}

  SELECT * FROM (
    SELECT T.*, ROWNUM AS rn FROM (
      SELECT s.item_id,
         s.item_title,
         s.item_price,
         i.image_url
          FROM shop_board s
              INNER JOIN (
              SELECT item_id, image_url
              FROM (
              SELECT item_id,
              image_url,
              ROW_NUMBER() OVER (PARTITION BY item_id ORDER BY image_uuid asc) rn
              FROM image_info
              WHERE image_url IS NOT NULL
              )
              WHERE rn = 1
              ) i ON s.item_id = i.item_id
          WHERE 1=1

              AND s.CATEGORY = #{category}

          ORDER BY s.item_id DESC
      ) T WHERE ROWNUM <= (#{offset}+1) * #{size}
) WHERE rn > #{offset} * #{size}
